import os

# 查找技能文件位置
skill_paths = []
for root, dirs, files in os.walk("."):
    for f in files:
        if f.endswith((".md", ".txt", ".yaml", ".yml", ".json")) or "小红书" in f:
            skill_paths.append(os.path.join(root, f))

# 也搜索隐藏目录
for root, dirs, files in os.walk("."):
    # 搜索包含"skill"或"小红书"的文件
    for f in files:
        if "skill" in f.lower() or "小红书" in f or "xhs" in f.lower() or "redbook" in f.lower():
            skill_paths.append(os.path.join(root, f))

# 去重
skill_paths = list(set(skill_paths))
for p in skill_paths:
